const row = $json;

// Numbers
const selling_price = Number(row.selling_price ?? 0);
const units_sold = Number(row.units_sold ?? 0);
const cost_per_unit = Number(row.cost_per_unit ?? 0);

// Calculations
const revenue = selling_price * units_sold;
const cost = cost_per_unit * units_sold;
const profit = revenue - cost;
const margin = revenue ? Number(((profit / revenue) * 100).toFixed(2)) : 0;

// Clean fields
const product_id = String(row.product_id ?? "").trim();
const month = String(row.month ?? "").trim().toLowerCase();

// Unique key (FIXED)
const product_id_month = `${product_id}_${month}`;

return {
  json: {
    product_id,
    product_name: row.product_name ?? "",
    category: row.category ?? "",
    cost_per_unit,
    selling_price,
    units_sold,
    month,
    revenue,
    profit,
    margin,
    product_id_month
  }
};

let sql = $json.output || $json.query || "";

// Clean SQL
sql = String(sql).replace(/```sql|```/gi, '').trim();

// Normalize AFTER cleaning
let lowerSQL = sql.toLowerCase();

// Block dangerous queries
const forbidden = ['insert', 'update', 'delete', 'drop', 'alter', 'truncate', 'create', 'replace'];

for (let word of forbidden) {
  if (lowerSQL.includes(word)) {
    throw new Error("Unsafe SQL detected!");
  }
}

// Ensure SELECT only
if (!lowerSQL.startsWith('select')) {
  sql = "SELECT * FROM sales_data LIMIT 5";
}

// 🔥 IMPORTANT: re-check AFTER possible changes
lowerSQL = sql.toLowerCase();

// Ensure LIMIT exists ONLY ONCE
if (!lowerSQL.includes('limit')) {
  sql += " LIMIT 10";
}

// Return
return [
  {
    json: {
      query: sql
    }
  }
];

const data = $input.all();

// 1. Handle empty data
if (!data || data.length === 0) {
  return [
    {
      json: {
        summary: "No data found"
      }
    }
  ];
}

// 2. Extract clean JSON
const cleaned = data.map(item => item.json);

// 3. Return BOTH structured + readable
return [
  {
    json: {
      data: cleaned,
      summary: JSON.stringify(cleaned, null, 2),
      row_count: cleaned.length
    }
  }
];
